import{_ as t,I as d,g as o,j as c}from"./chunks/framework.CbuNJfvM.js";const p=JSON.parse('{"title":".NET integration","description":"","frontmatter":{},"headers":[],"relativePath":"dotnet-integration.md","filePath":"dotnet-integration.md"}'),a={name:"dotnet-integration.md"};function r(n,e,l,i,s,m){return d(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="net-integration" tabindex="-1">.NET integration <a class="header-anchor" href="#net-integration" aria-label="Permalink to &quot;.NET integration&quot;">​</a></h1><p>ghūl is hosted on and targets .NET 8 and can consume most types in .NET assemblies built with C#.</p><h2 id="projects" tabindex="-1">projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;projects&quot;">​</a></h2><p>The ghūl compiler is driven by MSBuild and leverages the .NET SDK targets for most of the build process. Provided you reference the ghūl runtime library package, things should work as you&#39;d expect for any other .NET SDK project. You can add package references, build assemblies and pack NuGet packages etc. all using the normal <code>dotnet</code> command line tools.</p><h2 id="name-mangling" tabindex="-1">name mangling <a class="header-anchor" href="#name-mangling" aria-label="Permalink to &quot;name mangling&quot;">​</a></h2><p>When consuming C# code the ghūl compiler transforms symbol names to better match ghūl conventions:</p><ul><li>Class, struct and trait (=interface) names are left unchanged</li><li>Any generic type argument count suffix is left as-is (for example <code>KeyValuePair`2</code>)</li><li>Enum names and enum member names are transformed to <code>MACRO_CASE</code></li><li>Method, property and field names are transformed to <code>snake_case</code></li><li>Names that conflict with ghūl keywords are prefixed with <code>`</code></li></ul><h2 id="namespace-and-type-name-re-mapping" tabindex="-1">namespace and type name re-mapping <a class="header-anchor" href="#namespace-and-type-name-re-mapping" aria-label="Permalink to &quot;namespace and type name re-mapping&quot;">​</a></h2><p>Some commonly used namespace and type names are re-mapped in line with ghūl conventions</p><h3 id="namespaces" tabindex="-1">namespaces <a class="header-anchor" href="#namespaces" aria-label="Permalink to &quot;namespaces&quot;">​</a></h3><ul><li><code>System.Collections.Generic</code> is mapped to <code>Collections</code></li><li><code>System.IO</code> is mapped to <code>IO</code></li></ul><h3 id="framework-and-collection-types" tabindex="-1">framework and collection types <a class="header-anchor" href="#framework-and-collection-types" aria-label="Permalink to &quot;framework and collection types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Original Type</th><th>Mapped Type</th></tr></thead><tbody><tr><td><code>System.IDisposable</code></td><td><code>Ghul.Disposable</code></td></tr><tr><td><code>System.Type</code></td><td><code>System.Type2</code></td></tr><tr><td><code>System.Console</code></td><td><code>IO.Std</code></td></tr><tr><td><code>System.Collections.IEnumerable</code></td><td><code>Collections.NonGenericIterable</code></td></tr><tr><td><code>System.Collections.Generic.IReadOnlyCollection</code></td><td><code>Collections.Bag</code></td></tr><tr><td><code>System.Collections.Generic.ICollection</code></td><td><code>Collections.MutableBag</code></td></tr><tr><td><code>System.Collections.IEnumerator</code></td><td><code>Collections.MoveNext</code></td></tr><tr><td><code>System.Collections.Generic.IEnumerable</code></td><td><code>Collections.Iterable</code></td></tr><tr><td><code>System.Collections.Generic.IEnumerator</code></td><td><code>Collections.Iterator</code></td></tr><tr><td><code>System.Collections.Generic.IReadOnlyList</code></td><td><code>Collections.List</code></td></tr><tr><td><code>System.Collections.Generic.IList</code></td><td><code>Collections.MutableList</code></td></tr><tr><td><code>System.Collections.Generic.List</code></td><td><code>Collections.LIST</code></td></tr><tr><td><code>System.Collections.Generic.IReadOnlyDictionary</code></td><td><code>Collections.Map</code></td></tr><tr><td><code>System.Collections.Generic.IDictionary</code></td><td><code>Collections.MutableMap</code></td></tr><tr><td><code>System.Collections.Generic.Dictionary</code></td><td><code>Collections.MAP</code></td></tr><tr><td><code>System.Collections.Generic.HashSet</code></td><td><code>Collections.SET</code></td></tr><tr><td><code>System.Collections.Generic.Stack</code></td><td><code>Collections.STACK</code></td></tr></tbody></table><h3 id="primitive-types" tabindex="-1">primitive types <a class="header-anchor" href="#primitive-types" aria-label="Permalink to &quot;primitive types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Original Type</th><th>Mapped Type</th></tr></thead><tbody><tr><td><code>System.Void</code></td><td><code>Ghul.void</code></td></tr><tr><td><code>System.Boolean</code></td><td><code>Ghul.bool</code></td></tr><tr><td><code>System.Char</code></td><td><code>Ghul.char</code></td></tr><tr><td><code>System.Byte</code></td><td><code>Ghul.ubyte</code></td></tr><tr><td><code>System.SByte</code></td><td><code>Ghul.byte</code></td></tr><tr><td><code>System.UInt16</code></td><td><code>Ghul.ushort</code></td></tr><tr><td><code>System.Int16</code></td><td><code>Ghul.short</code></td></tr><tr><td><code>System.UInt32</code></td><td><code>Ghul.uint</code></td></tr><tr><td><code>System.Int32</code></td><td><code>Ghul.int</code></td></tr><tr><td><code>System.UInt64</code></td><td><code>Ghul.ulong</code></td></tr><tr><td><code>System.Int64</code></td><td><code>Ghul.long</code></td></tr><tr><td><code>System.UIntPtr</code></td><td><code>Ghul.uword</code></td></tr><tr><td><code>System.IntPtr</code></td><td><code>Ghul.word</code></td></tr><tr><td><code>System.Single</code></td><td><code>Ghul.single</code></td></tr><tr><td><code>System.Double</code></td><td><code>Ghul.double</code></td></tr><tr><td><code>System.Object</code></td><td><code>Ghul.object</code></td></tr><tr><td><code>System.String</code></td><td><code>Ghul.string</code></td></tr></tbody></table>',15)])])}const y=t(a,[["render",r]]);export{p as __pageData,y as default};
